INSERT INTO lessons_mirror (id, as_of_date, doc_title, canonical_url, sections_json, generator, status, template_ver) VALUES ('L-2026-07-15-2607.11459', '2026-07-15', 'A Multimodal Dataset for Large Language Model Applications in the Energy Domain', 'https://arxiv.org/abs/2607.11459v1', '[{"title": "人话版", "sentences": [{"text": "这篇论文在做什么：This paper presents the mAIEnergy dataset, an open-access, multimodal corpus developed to support Large Language Model (LLM) applications in the energy sector.", "claim": "arxiv:2607.11459#v1:c0"}, {"text": "论文《A Multimodal Dataset for Large Language Model Applications in the Energy Domain》发表于 2026-07-13，作者 2 人，原文见 https://arxiv.org/abs/2607.11459v1。", "claim": "__doc_meta__"}], "body": "这篇论文在做什么：This paper presents the mAIEnergy dataset, an open-access, multimodal corpus developed to support Large Language Model (LLM) applications in the energy sector. 论文《A Multimodal Dataset for Large Language Model Applications in the Energy Domain》发表于 2026-07-13，作者 2 人，原文见 https://arxiv.org/abs/2607.11459v1。"}, {"title": "领域脉络", "sentences": [{"text": "本文主类目 eess.SY：系统与控制工程——让复杂系统按预期稳定运行。", "claim": "__doc_meta__"}, {"text": "交叉类目 cs.AI：人工智能——让机器完成需要智能的任务的总领域。", "claim": "__doc_meta__"}], "body": "本文主类目 eess.SY：系统与控制工程——让复杂系统按预期稳定运行。 交叉类目 cs.AI：人工智能——让机器完成需要智能的任务的总领域。"}, {"title": "机制拆解", "sentences": [{"text": "This paper presents the mAIEnergy dataset, an open-access, multimodal corpus developed to support Large Language Model (LLM) applications in the energy sector.", "claim": "arxiv:2607.11459#v1:c0"}], "body": "This paper presents the mAIEnergy dataset, an open-access, multimodal corpus developed to support Large Language Model (LLM) applications in the energy sector."}, {"title": "证据与数字", "sentences": [{"text": "The dataset integrates approximately 50,000 textual documents, 20,000 images, 25 million numerical time series records, and 2 million geospatial and relational data entries.", "claim": "arxiv:2607.11459#v1:c1"}], "body": "The dataset integrates approximately 50,000 textual documents, 20,000 images, 25 million numerical time series records, and 2 million geospatial and relational data entries."}, {"title": "反例与边界", "sentences": [{"text": "摘要未声明边界与反例——这是一个需要警惕的信号，深挖时先问局限。", "claim": "__doc_meta__"}], "body": "摘要未声明边界与反例——这是一个需要警惕的信号，深挖时先问局限。"}, {"title": "跨领域连接与意外收获", "sentences": [{"text": "本文横跨 2 个类目（eess.SY, cs.AI），关注其在你兴趣板块间的迁移面。", "claim": "__doc_meta__"}, {"text": "意外收获：本文由 2 位作者合作完成，发表后 48 小时内即进入你的学习队列。", "claim": "__doc_meta__"}, {"text": "意外收获：本篇的入选是 8 特征加权的结果——打开系统页可以看到它赢在哪个特征。", "claim": "__doc_meta__"}], "body": "本文横跨 2 个类目（eess.SY, cs.AI），关注其在你兴趣板块间的迁移面。 意外收获：本文由 2 位作者合作完成，发表后 48 小时内即进入你的学习队列。 意外收获：本篇的入选是 8 特征加权的结果——打开系统页可以看到它赢在哪个特征。"}, {"title": "可复用方法", "sentences": [{"text": "This paper presents the mAIEnergy dataset, an open-access, multimodal corpus developed to support Large Language Model (LLM) applications in the energy sector.", "claim": "arxiv:2607.11459#v1:c0"}], "body": "This paper presents the mAIEnergy dataset, an open-access, multimodal corpus developed to support Large Language Model (LLM) applications in the energy sector."}, {"title": "术语表", "sentences": [{"text": "术语 LLM——出处见声明：This paper presents the mAIEnergy dataset, an open-access, multimodal corpus…", "claim": "arxiv:2607.11459#v1:c0"}, {"text": "术语 FAIR——出处见声明：The mAIEnergy dataset adheres to Findable, Accessible, Interoperable, and…", "claim": "arxiv:2607.11459#v1:c5"}], "body": "术语 LLM——出处见声明：This paper presents the mAIEnergy dataset, an open-access, multimodal corpus… 术语 FAIR——出处见声明：The mAIEnergy dataset adheres to Findable, Accessible, Interoperable, and…"}]', 'deterministic_degraded', 'open', 'lesson-v03-2');
INSERT INTO lessons_mirror (id, as_of_date, doc_title, canonical_url, sections_json, generator, status, template_ver) VALUES ('L-2026-07-14-2607.06008', '2026-07-14', 'PolyWorkBench: Benchmarking Multilingual Long-Horizon LLM Agents', 'https://arxiv.org/abs/2607.06008v2', '[{"title": "人话版", "sentences": [{"text": "这篇论文在做什么：Large language model (LLM) agents have shown strong performance in long-horizon tasks that require planning, tool use, and interaction with external environments.", "claim": "arxiv:2607.06008#v2:c0"}, {"text": "论文《PolyWorkBench: Benchmarking Multilingual Long-Horizon LLM Agents》发表于 2026-07-07，作者 8 人，原文见 https://arxiv.org/abs/2607.06008v2。", "claim": "__doc_meta__"}], "body": "这篇论文在做什么：Large language model (LLM) agents have shown strong performance in long-horizon tasks that require planning, tool use, and interaction with external environments. 论文《PolyWorkBench: Benchmarking Multilingual Long-Horizon LLM Agents》发表于 2026-07-07，作者 8 人，原文见 https://arxiv.org/abs/2607.06008v2。"}, {"title": "领域脉络", "sentences": [{"text": "本文主类目 cs.AI：人工智能——让机器完成需要智能的任务的总领域。", "claim": "__doc_meta__"}, {"text": "交叉类目 cs.CL：自然语言处理——让机器理解与生成人类语言。", "claim": "__doc_meta__"}], "body": "本文主类目 cs.AI：人工智能——让机器完成需要智能的任务的总领域。 交叉类目 cs.CL：自然语言处理——让机器理解与生成人类语言。"}, {"title": "机制拆解", "sentences": [{"text": "In this work, we introduce PolyWorkBench, a benchmark for evaluating LLM agents on multilingual long-horizon workplace workflows.", "claim": "arxiv:2607.06008#v2:c3"}, {"text": "To enable comprehensive evaluation, we propose a hybrid framework that combines structural grading, executable verification, and LLM-based semantic assessment.", "claim": "arxiv:2607.06008#v2:c5"}, {"text": "This design allows us to capture both functional correctness and linguistic consistency across complex workflows.", "claim": "arxiv:2607.06008#v2:c6"}], "body": "In this work, we introduce PolyWorkBench, a benchmark for evaluating LLM agents on multilingual long-horizon workplace workflows. To enable comprehensive evaluation, we propose a hybrid framework that combines structural grading, executable verification, and LLM-based semantic assessment. This design allows us to capture both functional correctness and linguistic consistency across complex workflows."}, {"title": "证据与数字", "sentences": [{"text": "PolyWorkBench consists of 67 tasks across five domains, including commerce, knowledge work, legal analysis, localization, and manufacturing, where agents must process heterogeneous multilingual inputs, perform iterative reasoning, invoke external tools, and produce structured outputs.", "claim": "arxiv:2607.06008#v2:c4"}], "body": "PolyWorkBench consists of 67 tasks across five domains, including commerce, knowledge work, legal analysis, localization, and manufacturing, where agents must process heterogeneous multilingual inputs, perform iterative reasoning, invoke external tools, and produce structured outputs."}, {"title": "反例与边界", "sentences": [{"text": "However, most existing benchmarks implicitly assume a monolingual setting, where the entire execution process, including reasoning, tool invocation, and output generation, is conducted within a single language.", "claim": "arxiv:2607.06008#v2:c1"}], "body": "However, most existing benchmarks implicitly assume a monolingual setting, where the entire execution process, including reasoning, tool invocation, and output generation, is conducted within a single language."}, {"title": "跨领域连接与意外收获", "sentences": [{"text": "本文横跨 2 个类目（cs.AI, cs.CL），关注其在你兴趣板块间的迁移面。", "claim": "__doc_meta__"}, {"text": "意外收获：However, most existing benchmarks implicitly assume a monolingual setting, where the entire execution process, including reasoning, tool invocation, and output generation, is conducted within a single language.", "claim": "arxiv:2607.06008#v2:c1"}, {"text": "意外收获：Our analysis suggests that multilinguality introduces compounding effects across reasoning and execution steps, highlighting the importance of jointly modeling language variation and procedural decision-making in agent evaluation.", "claim": "arxiv:2607.06008#v2:c8"}], "body": "本文横跨 2 个类目（cs.AI, cs.CL），关注其在你兴趣板块间的迁移面。 意外收获：However, most existing benchmarks implicitly assume a monolingual setting, where the entire execution process, including reasoning, tool invocation, and output generation, is conducted within a single language. 意外收获：Our analysis suggests that multilinguality introduces compounding effects across reasoning and execution steps, highlighting the importance of jointly modeling language variation and procedural decision-making in agent evaluation."}, {"title": "可复用方法", "sentences": [{"text": "In this work, we introduce PolyWorkBench, a benchmark for evaluating LLM agents on multilingual long-horizon workplace workflows.", "claim": "arxiv:2607.06008#v2:c3"}], "body": "In this work, we introduce PolyWorkBench, a benchmark for evaluating LLM agents on multilingual long-horizon workplace workflows."}, {"title": "术语表", "sentences": [{"text": "术语 LLM——出处见声明：Large language model (LLM) agents have shown strong performance in long-horizon ", "claim": "arxiv:2607.06008#v2:c0"}, {"text": "术语 PolyWorkBench——出处见声明：In this work, we introduce PolyWorkBench, a benchmark for evaluating LLM agents ", "claim": "arxiv:2607.06008#v2:c3"}], "body": "术语 LLM——出处见声明：Large language model (LLM) agents have shown strong performance in long-horizon  术语 PolyWorkBench——出处见声明：In this work, we introduce PolyWorkBench, a benchmark for evaluating LLM agents "}]', 'deterministic_degraded', 'open', 'lesson-v03-2');
INSERT INTO lessons_mirror (id, as_of_date, doc_title, canonical_url, sections_json, generator, status, template_ver) VALUES ('L-2026-07-13-2607.05876', '2026-07-13', 'Think Before You Grid-Search: Floor-First Triage for LLM Serving', 'https://arxiv.org/abs/2607.05876v2', '[{"title": "人话版", "sentences": [{"text": "这篇论文在做什么：LLM serving optimization typically benchmarks many configurations and reaches for heavy profilers when latency targets are missed.", "claim": "arxiv:2607.05876#v2:c0"}, {"text": "论文《Think Before You Grid-Search: Floor-First Triage for LLM Serving》发表于 2026-07-07，作者 1 人，原文见 https://arxiv.org/abs/2607.05876v2。", "claim": "__doc_meta__"}], "body": "这篇论文在做什么：LLM serving optimization typically benchmarks many configurations and reaches for heavy profilers when latency targets are missed. 论文《Think Before You Grid-Search: Floor-First Triage for LLM Serving》发表于 2026-07-07，作者 1 人，原文见 https://arxiv.org/abs/2607.05876v2。"}, {"title": "领域脉络", "sentences": [{"text": "本文主类目 cs.PF：（该类目暂无脉络注解，点原文了解）。", "claim": "__doc_meta__"}, {"text": "交叉类目 cs.AI：人工智能——让机器完成需要智能的任务的总领域。", "claim": "__doc_meta__"}], "body": "本文主类目 cs.PF：（该类目暂无脉络注解，点原文了解）。 交叉类目 cs.AI：人工智能——让机器完成需要智能的任务的总领域。"}, {"title": "机制拆解", "sentences": [{"text": "LLM serving optimization typically benchmarks many configurations and reaches for heavy profilers when latency targets are missed.", "claim": "arxiv:2607.05876#v2:c0"}, {"text": "We argue for the reverse discipline: estimation is the analytical layer of profiling -- without it, optimization degenerates to grid search.", "claim": "arxiv:2607.05876#v2:c1"}], "body": "LLM serving optimization typically benchmarks many configurations and reaches for heavy profilers when latency targets are missed. We argue for the reverse discipline: estimation is the analytical layer of profiling -- without it, optimization degenerates to grid search."}, {"title": "证据与数字", "sentences": [{"text": "As a case study we analyze a DeepSeek-V3.2-style 671B MoE/MLA model on 16 NVIDIA H20 GPUs, whose ridge point of ~74 FLOP/byte (vs ~590 for H100) makes it an extreme decode-oriented part.", "claim": "arxiv:2607.05876#v2:c7"}, {"text": "The floors show TP16 decoding is KV-capacity-limited to ~70 concurrent 8K requests; sparse attention removes the KV-bandwidth term but not the capacity wall; an EP16+DP-attention layout accepts slightly worse same-batch weight traffic for an order-of-magnitude higher capacity wall (~644) -- while single-stream latency favors TP by 2.4x.", "claim": "arxiv:2607.05876#v2:c8"}], "body": "As a case study we analyze a DeepSeek-V3.2-style 671B MoE/MLA model on 16 NVIDIA H20 GPUs, whose ridge point of ~74 FLOP/byte (vs ~590 for H100) makes it an extreme decode-oriented part. The floors show TP16 decoding is KV-capacity-limited to ~70 concurrent 8K requests; sparse attention removes the KV-bandwidth term but not the capacity wall; an EP16+DP-attention layout accepts slightly worse same-batch weight traffic for an order-of-magnitude higher capacity wall (~644) -- while single-stream latency favors TP by 2.4x."}, {"title": "反例与边界", "sentences": [{"text": "Where a measurement lands inside this [max, sum] interval reads out overlap quality before any profiler is opened, and profilers escalate only on residuals above a stated threshold.", "claim": "arxiv:2607.05876#v2:c4"}, {"text": "The floors show TP16 decoding is KV-capacity-limited to ~70 concurrent 8K requests; sparse attention removes the KV-bandwidth term but not the capacity wall; an EP16+DP-attention layout accepts slightly worse same-batch weight traffic for an order-of-magnitude higher capacity wall (~644) -- while single-stream latency favors TP by 2.4x.", "claim": "arxiv:2607.05876#v2:c8"}], "body": "Where a measurement lands inside this [max, sum] interval reads out overlap quality before any profiler is opened, and profilers escalate only on residuals above a stated threshold. The floors show TP16 decoding is KV-capacity-limited to ~70 concurrent 8K requests; sparse attention removes the KV-bandwidth term but not the capacity wall; an EP16+DP-attention layout accepts slightly worse same-batch weight traffic for an order-of-magnitude higher capacity wall (~644) -- while single-stream latency favors TP by 2.4x."}, {"title": "跨领域连接与意外收获", "sentences": [{"text": "本文横跨 3 个类目（cs.PF, cs.AI, cs.DC），关注其在你兴趣板块间的迁移面。", "claim": "__doc_meta__"}, {"text": "意外收获：The floors show TP16 decoding is KV-capacity-limited to ~70 concurrent 8K requests; sparse attention removes the KV-bandwidth term but not the capacity wall; an EP16+DP-attention layout accepts slightly worse same-batch weight traffic for an order-of-magnitude higher capacity wall (~644) -- while single-stream latency favors TP by 2.4x.", "claim": "arxiv:2607.05876#v2:c8"}, {"text": "意外收获：本文由 1 位作者合作完成，发表后 48 小时内即进入你的学习队列。", "claim": "__doc_meta__"}], "body": "本文横跨 3 个类目（cs.PF, cs.AI, cs.DC），关注其在你兴趣板块间的迁移面。 意外收获：The floors show TP16 decoding is KV-capacity-limited to ~70 concurrent 8K requests; sparse attention removes the KV-bandwidth term but not the capacity wall; an EP16+DP-attention layout accepts slightly worse same-batch weight traffic for an order-of-magnitude higher capacity wall (~644) -- while single-stream latency favors TP by 2.4x. 意外收获：本文由 1 位作者合作完成，发表后 48 小时内即进入你的学习队列。"}, {"title": "可复用方法", "sentences": [{"text": "可复用方法：将本文机制与你正在跟的项目对照，找一个能在两周内验证的最小实验。", "claim": "__doc_meta__"}], "body": "可复用方法：将本文机制与你正在跟的项目对照，找一个能在两周内验证的最小实验。"}, {"title": "术语表", "sentences": [{"text": "术语 LLM——出处见声明：LLM serving optimization typically benchmarks many configurations and reaches fo", "claim": "arxiv:2607.05876#v2:c0"}, {"text": "术语 HBM——出处见声明：Each decode step is modeled as a five-dimensional resource vector (HBM bytes, FL", "claim": "arxiv:2607.05876#v2:c3"}, {"text": "术语 FLOPs——出处见声明：Each decode step is modeled as a five-dimensional resource vector (HBM bytes, FL", "claim": "arxiv:2607.05876#v2:c3"}, {"text": "术语 DeepSeek——出处见声明：As a case study we analyze a DeepSeek-V3.2-style 671B MoE/MLA model on 16 NVIDIA", "claim": "arxiv:2607.05876#v2:c7"}, {"text": "术语 MoE——出处见声明：As a case study we analyze a DeepSeek-V3.2-style 671B MoE/MLA model on 16 NVIDIA", "claim": "arxiv:2607.05876#v2:c7"}, {"text": "术语 MLA——出处见声明：As a case study we analyze a DeepSeek-V3.2-style 671B MoE/MLA model on 16 NVIDIA", "claim": "arxiv:2607.05876#v2:c7"}], "body": "术语 LLM——出处见声明：LLM serving optimization typically benchmarks many configurations and reaches fo 术语 HBM——出处见声明：Each decode step is modeled as a five-dimensional resource vector (HBM bytes, FL 术语 FLOPs——出处见声明：Each decode step is modeled as a five-dimensional resource vector (HBM bytes, FL 术语 DeepSeek——出处见声明：As a case study we analyze a DeepSeek-V3.2-style 671B MoE/MLA model on 16 NVIDIA 术语 MoE——出处见声明：As a case study we analyze a DeepSeek-V3.2-style 671B MoE/MLA model on 16 NVIDIA 术语 MLA——出处见声明：As a case study we analyze a DeepSeek-V3.2-style 671B MoE/MLA model on 16 NVIDIA"}]', 'deterministic_degraded', 'open', 'lesson-v03-2');
INSERT INTO lessons_mirror (id, as_of_date, doc_title, canonical_url, sections_json, generator, status, template_ver) VALUES ('L-2026-07-12-2607.06605', '2026-07-12', 'A Quiet Failure in Calibrated Virtual Screening: Marginal Conformal Prediction Under-Covers the Minority Class, and a Class-Conditional Fix Recovers It', 'https://arxiv.org/abs/2607.06605v1', '[{"title": "人话版", "sentences": [{"text": "这篇论文在做什么：We show this guarantee can be dangerous on imbalanced datasets.", "claim": "arxiv:2607.06605#v1:c1"}, {"text": "论文《A Quiet Failure in Calibrated Virtual Screening: Marginal Conformal Prediction Under-Covers the Minority Class, and a Class-Conditional Fix Recovers It》发表于 2026-07-07，作者 2 人，原文见 https://arxiv.org/abs/2607.06605v1。", "claim": "__doc_meta__"}], "body": "这篇论文在做什么：We show this guarantee can be dangerous on imbalanced datasets. 论文《A Quiet Failure in Calibrated Virtual Screening: Marginal Conformal Prediction Under-Covers the Minority Class, and a Class-Conditional Fix Recovers It》发表于 2026-07-07，作者 2 人，原文见 https://arxiv.org/abs/2607.06605v1。"}, {"title": "领域脉络", "sentences": [{"text": "本文主类目 cs.LG：机器学习——从数据中自动学习规律的方法学。", "claim": "__doc_meta__"}, {"text": "交叉类目 stat.ML：统计机器学习——机器学习的统计学基础。", "claim": "__doc_meta__"}], "body": "本文主类目 cs.LG：机器学习——从数据中自动学习规律的方法学。 交叉类目 stat.ML：统计机器学习——机器学习的统计学基础。"}, {"title": "机制拆解", "sentences": [{"text": "Conformal prediction is being adopted in drug discovery to put an honest number on model reliability: pick an error rate alpha, and the method returns prediction sets containing the true label with probability at least 1 - alpha.", "claim": "arxiv:2607.06605#v1:c0"}, {"text": "We localize the failures to generic molecular scaffolds - plain benzene and pyridine cores occurring in both classes - propose a one-number diagnostic, and show with a cost model that abstaining on affected compounds flips a screening campaign from net-negative to net-positive utility.", "claim": "arxiv:2607.06605#v1:c7"}], "body": "Conformal prediction is being adopted in drug discovery to put an honest number on model reliability: pick an error rate alpha, and the method returns prediction sets containing the true label with probability at least 1 - alpha. We localize the failures to generic molecular scaffolds - plain benzene and pyridine cores occurring in both classes - propose a one-number diagnostic, and show with a cost model that abstaining on affected compounds flips a screening campaign from net-negative to net-positive utility."}, {"title": "证据与数字", "sentences": [{"text": "Across four datasets, standard (marginal) conformal prediction hits its global 90% coverage target while leaving the minority class badly exposed: realized minority coverage falls to 64.8% on blood-brain-barrier penetration and to 4.2% on clinical-trial toxicity, where the rare class is nearly abandoned.", "claim": "arxiv:2607.06605#v1:c2"}, {"text": "The failure is not tied to one model: a random forest, a graph network, and a frozen chemical language model all reproduce it (p < 0.001 in every case), with severity tracking baseline calibration on rare labels rather than architecture.", "claim": "arxiv:2607.06605#v1:c3"}], "body": "Across four datasets, standard (marginal) conformal prediction hits its global 90% coverage target while leaving the minority class badly exposed: realized minority coverage falls to 64.8% on blood-brain-barrier penetration and to 4.2% on clinical-trial toxicity, where the rare class is nearly abandoned. The failure is not tied to one model: a random forest, a graph network, and a frozen chemical language model all reproduce it (p < 0.001 in every case), with severity tracking baseline calibration on rare labels rather than architecture."}, {"title": "反例与边界", "sentences": [{"text": "The failure is not tied to one model: a random forest, a graph network, and a frozen chemical language model all reproduce it (p < 0.001 in every case), with severity tracking baseline calibration on rare labels rather than architecture.", "claim": "arxiv:2607.06605#v1:c3"}, {"text": "The failure survives realistic scaffold splits and a second conformal score, while aggregate accuracy and overall coverage stay reassuringly high, which is exactly why it is easy to miss.", "claim": "arxiv:2607.06605#v1:c5"}], "body": "The failure is not tied to one model: a random forest, a graph network, and a frozen chemical language model all reproduce it (p < 0.001 in every case), with severity tracking baseline calibration on rare labels rather than architecture. The failure survives realistic scaffold splits and a second conformal score, while aggregate accuracy and overall coverage stay reassuringly high, which is exactly why it is easy to miss."}, {"title": "跨领域连接与意外收获", "sentences": [{"text": "本文横跨 2 个类目（cs.LG, stat.ML），关注其在你兴趣板块间的迁移面。", "claim": "__doc_meta__"}, {"text": "意外收获：Across four datasets, standard (marginal) conformal prediction hits its global 90% coverage target while leaving the minority class badly exposed: realized minority coverage falls to 64.8% on blood-brain-barrier penetration and to 4.2% on clinical-trial toxicity, where the rare class is nearly abandoned.", "claim": "arxiv:2607.06605#v1:c2"}, {"text": "意外收获：The failure is not tied to one model: a random forest, a graph network, and a frozen chemical language model all reproduce it (p < 0.001 in every case), with severity tracking baseline calibration on rare labels rather than architecture.", "claim": "arxiv:2607.06605#v1:c3"}], "body": "本文横跨 2 个类目（cs.LG, stat.ML），关注其在你兴趣板块间的迁移面。 意外收获：Across four datasets, standard (marginal) conformal prediction hits its global 90% coverage target while leaving the minority class badly exposed: realized minority coverage falls to 64.8% on blood-brain-barrier penetration and to 4.2% on clinical-trial toxicity, where the rare class is nearly abandoned. 意外收获：The failure is not tied to one model: a random forest, a graph network, and a frozen chemical language model all reproduce it (p < 0.001 in every case), with severity tracking baseline calibration on rare labels rather than architecture."}, {"title": "可复用方法", "sentences": [{"text": "Conformal prediction is being adopted in drug discovery to put an honest number on model reliability: pick an error rate alpha, and the method returns prediction sets containing the true label with probability at least 1 - alpha.", "claim": "arxiv:2607.06605#v1:c0"}], "body": "Conformal prediction is being adopted in drug discovery to put an honest number on model reliability: pick an error rate alpha, and the method returns prediction sets containing the true label with probability at least 1 - alpha."}, {"title": "术语表", "sentences": [{"text": "摘要未出现需要解释的专有术语。", "claim": "__doc_meta__"}], "body": "摘要未出现需要解释的专有术语。"}]', 'deterministic_degraded', 'open', 'lesson-v03-2');
